sys_ux_macroponent.internal_event_mappings:
{
    "MACROPONENT_READY": [
        {
            "broker": null,
            "clientScript": null,
            "conditional": null,
            "declarativeAction": null,
            "event": {
                "apiName": "sn_uxf.MACROPONENT_TRACK_USAGE_REQUESTED",
                "payload": {
                    "script": {
                        "apiVersion": "1.0.0",
                        "controllerElementId": null,
                        "inlineScript": "/**\n* @param {params} params\n* @param {api} params.api\n* @param {any} params.event\n*/\nfunction evaluateEvent({api, event}) {\n\tvar roles = api.context.session.user.roles;\n\tvar role = roles.join(',');\n\tif (roles.includes('sn_cmdb_admin') || roles.includes('admin') || roles.includes('maint')) {\n\t\trole = 'sn_cmdb_admin';\n\t} else if (roles.includes('sn_cmdb_editor')) {\n\t\trole = 'sn_cmdb_editor';\n\t} else if (roles.includes('sn_cmdb_user')) {\n\t\trole = 'sn_cmdb_user';\n\t}\n\treturn {\n\t\tevent: 'Explore CI: Form Opened',\n\t\tvalue: {'class': api.context.props.table, 'role': role}\n\t};\n}",
                        "scriptSysId": null,
                        "target": null
                    },
                    "type": "CLIENT_TRANSFORM_SCRIPT"
                },
                "sysId": "66375ab240edff20524ba9b56584fad0"
            },
            "operation": null,
            "targetId": "WInFxvWMDUMffjjfYODskaccrRee",
            "type": "EVENT"
        }
    ]
}
